1615	// readActiveSessionLog reads the latest session log entries for an active worker.
1616	// Canonical service-event output is written as svc-*.jsonl inside the embedded
1617	// execution bundle; legacy agent-*.jsonl remains supported as a fallback.
1618	func (m *WorkerManager) readActiveSessionLog(handle *workerHandle) string {
1619		candidates := m.activeSessionLogCandidates()
1620		if len(candidates) == 0 {
1621			return ""
1622		}
1623		sort.SliceStable(candidates, func(i, j int) bool {
1624			if candidates[i].canonical != candidates[j].canonical {
1625				return candidates[i].canonical
1626			}
1627			return candidates[i].modTime.After(candidates[j].modTime)
1628		})
1629	
1630		// Read the last N lines of the preferred log and format them as readable progress.
1631		data, err := os.ReadFile(candidates[0].path)
1632		if err != nil {
1633			return ""
1634		}
1635	
1636		lines := strings.Split(strings.TrimSpace(string(data)), "\n")
1637		// Show the last 50 entries
1638		start := 0
1639		if len(lines) > 50 {
1640			start = len(lines) - 50
1641		}
1642	
1643		return formatActiveSessionLogLines(lines[start:])
1644	}
