1652	func (m *WorkerManager) activeSessionLogCandidates() []sessionLogCandidate {
1653		var candidates []sessionLogCandidate
1654		appendDir := func(dir string) {
1655			entries, err := os.ReadDir(dir)
1656			if err != nil {
1657				return
1658			}
1659			for _, entry := range entries {
1660				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".jsonl") {
1661					continue
1662				}
1663				// Skip loop event files — they contain loop milestones, not agent session
1664				// entries. Loop milestone progress is already captured in worker.log.
1665				if strings.HasPrefix(entry.Name(), "agent-loop-") {
1666					continue
1667				}
1668				canonical := strings.HasPrefix(entry.Name(), "svc-")
1669				if !canonical && !strings.HasPrefix(entry.Name(), "agent-") {
1670					continue
1671				}
1672				info, err := entry.Info()
1673				if err != nil {
1674					continue
1675				}
1676				candidates = append(candidates, sessionLogCandidate{
1677					path:      filepath.Join(dir, entry.Name()),
1678					canonical: canonical,
1679					modTime:   info.ModTime(),
1680				})
1681			}
1682		}
1683	
1684		appendDir(filepath.Join(m.projectRoot, ".ddx", "agent-logs"))
1685		embeddedDirs, _ := filepath.Glob(filepath.Join(m.projectRoot, ".ddx", "executions", "*", "embedded"))
1686		for _, dir := range embeddedDirs {
1687			appendDir(dir)
1688		}
1689		return candidates
1690	}
