1692	func formatActiveSessionLogLines(lines []string) string {
1693		var progress []agentlib.ServiceProgressData
1694		for _, line := range lines {
1695			line = strings.TrimSpace(line)
1696			if line == "" {
1697				continue
1698			}
1699			var entry map[string]any
1700			if err := json.Unmarshal([]byte(line), &entry); err != nil {
1701				continue
1702			}
1703			if typ, _ := entry["type"].(string); typ != agentlib.ServiceEventTypeProgress {
1704				continue
1705			}
1706			var data agentlib.ServiceProgressData
1707			rawData, err := json.Marshal(entry["data"])
1708			if err != nil {
1709				continue
1710			}
1711			if err := json.Unmarshal(rawData, &data); err != nil {
1712				continue
1713			}
1714			progress = append(progress, data)
1715		}
1716		if len(progress) > 0 {
1717			return agent.FormatServiceProgressEntries(progress)
1718		}
1719		return agent.FormatSessionLogLines(lines)
1720	}
