280	func normalizeISOTime(s string) string {
281		if s == "" {
282			return ""
283		}
284		if t, err := time.Parse(time.RFC3339Nano, s); err == nil {
285			return t.UTC().Format(time.RFC3339)
286		}
287		if t, err := time.Parse(time.RFC3339, s); err == nil {
288			return t.UTC().Format(time.RFC3339)
289		}
290		return s
291	}
