// FormatServiceProgressEntries formats canonical Fizeau progress payloads
// directly. It is used by callers that already have structured ServiceEvent
// data and should not round-trip through session-log JSONL line parsing.
func FormatServiceProgressEntries(entries []agentlib.ServiceProgressData) string {
	var sb strings.Builder
	for _, entry := range entries {
		raw, err := json.Marshal(entry)
		if err != nil {
			continue
		}
		var data map[string]any
		if err := json.Unmarshal(raw, &data); err != nil {
			continue
		}
		if line := formatProgressLogEntry(map[string]any{
			"type": "progress",
			"data": data,
		}); line != "" {
			sb.WriteString(line)
		}
	}
	return sb.String()
}

func truncateStr(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen-1] + "…"
}

type payloadHint struct {
	label string
	bytes int
}

func formatPayloadHints(hints []payloadHint) string {
	parts := make([]string, 0, len(hints))
	for _, hint := range hints {
		if hint.bytes <= 0 {
			continue
		}
		parts = append(parts, hint.label+"="+formatByteSize(hint.bytes))
	}
	return strings.Join(parts, " ")
}

func formatSizeSuffix(label string, bytes int) string {
	if bytes <= 0 {
		return ""
	}
	return ", " + label + "=" + formatByteSize(bytes)
}

func formatByteSize(bytes int) string {
	switch {
	case bytes <= 0:
		return "0B"
	case bytes < 1024:
		return fmt.Sprintf("%dB", bytes)
	case bytes < 1024*1024:
		return fmt.Sprintf("%.1fKB", float64(bytes)/1024)
	default:
		return fmt.Sprintf("%.1fMB", float64(bytes)/(1024*1024))
	}
}

func encodedPayloadSize(v any) int {
	if v == nil {
		return 0
	}
	switch x := v.(type) {
	case string:
		return len([]byte(x))
	case json.RawMessage:
		return len(x)
	case []byte:
		return len(x)
	default:
